1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  priorContracts: number;
4	  firstInsurance?: boolean;
5	};
6	
7	export type Item = Record<string, unknown>;
8	
9	export type Policy = {
10	  customer: Customer;
11	  items: Item[];
12	};
13	
14	export type QuoteResult = {
15	  premium: number;
16	};
17	
18	export type ClaimResult = {
19	  payout: number;
20	  remainingCap: number;
21	};
22	
23	const PROCESSING_FEE = 5;
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	
28	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  component: COMPONENT_BASE_PREMIUM,
34	};
35	
36	const basePremiumForItem = (item: Item): number =>
37	  BASE_PREMIUM_BY_ITEM_TYPE[item.type as string] ?? 0;
38	
39	const isComponent = (item: Item): boolean => item.type === "component";
40	
41	const groupComponentsByType = (items: Item[]): Map<string, number> => {
42	  const groups = new Map<string, number>();
43	  for (const item of items.filter(isComponent)) {
44	    const key = item.componentType as string;
45	    groups.set(key, (groups.get(key) ?? 0) + 1);
46	  }
47	  return groups;
48	};
49	
50	const componentGroupPremium = (count: number): number =>
51	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_BASE_PREMIUM;
52	
53	const componentsPremium = (items: Item[]): number =>
54	  Array.from(groupComponentsByType(items).values()).reduce(
55	    (sum, count) => sum + componentGroupPremium(count),
56	    0,
57	  );
58	
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	
63	type ItemModifier = (item: Item, base: number) => number;
64	
65	const curseModifier: ItemModifier = (item, base) =>
66	  item.cursed === true ? base * CURSE_SURCHARGE_RATE : 0;
67	
68	const highEnchantmentModifier: ItemModifier = (item, base) =>
69	  (item.enchantment as number) >= HIGH_ENCHANTMENT_THRESHOLD
70	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
71	    : 0;
72	
73	const ITEM_MODIFIERS: ItemModifier[] = [curseModifier, highEnchantmentModifier];
74	
75	const itemPremium = (item: Item): number => {
76	  const base = basePremiumForItem(item);
77	  return ITEM_MODIFIERS.reduce(
78	    (premium, modifier) => premium + modifier(item, base),
79	    base,
80	  );
81	};
82	
83	type NonComponentTotals = { base: number; withModifiers: number };
84	
85	const nonComponentsTotals = (items: Item[]): NonComponentTotals =>
86	  items
87	    .filter((item) => !isComponent(item))
88	    .reduce<NonComponentTotals>(
89	      (totals, item) => ({
90	        base: totals.base + basePremiumForItem(item),
91	        withModifiers: totals.withModifiers + itemPremium(item),
92	      }),
93	      { base: 0, withModifiers: 0 },
94	    );
95	
96	const LOYALTY_DISCOUNT_RATE = 0.2;
97	const LOYALTY_YEARS_THRESHOLD = 2;
98	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
99	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
100	const FOLLOW_UP_PRIOR_CONTRACTS_THRESHOLD = 1;
101	
102	type PolicyAdjustment = (customer: Customer, basePremium: number) => number;
103	
104	const loyaltyAdjustment: PolicyAdjustment = (customer, basePremium) =>
105	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
106	    ? -basePremium * LOYALTY_DISCOUNT_RATE
107	    : 0;
108	
109	const firstInsuranceAdjustment: PolicyAdjustment = (customer, basePremium) =>
110	  customer.firstInsurance === true ? basePremium * FIRST_INSURANCE_SURCHARGE_RATE : 0;
111	
112	const followUpAdjustment: PolicyAdjustment = (customer, basePremium) =>
113	  customer.priorContracts >= FOLLOW_UP_PRIOR_CONTRACTS_THRESHOLD
114	    ? -basePremium * FOLLOW_UP_DISCOUNT_RATE
115	    : 0;
116	
117	const POLICY_ADJUSTMENTS: PolicyAdjustment[] = [
118	  loyaltyAdjustment,
119	  firstInsuranceAdjustment,
120	  followUpAdjustment,
121	];
122	
123	const totalPolicyAdjustment = (customer: Customer, basePremium: number): number =>
124	  POLICY_ADJUSTMENTS.reduce(
125	    (sum, adjustment) => sum + adjustment(customer, basePremium),
126	    0,
127	  );
128	
129	export function quote(policy: Policy): QuoteResult {
130	  const componentsTotal = componentsPremium(policy.items);
131	  const nonComponents = nonComponentsTotals(policy.items);
132	  const itemsTotal = nonComponents.withModifiers + componentsTotal;
133	  const policyBase = nonComponents.base + componentsTotal;
134	  return {
135	    premium: Math.ceil(itemsTotal + totalPolicyAdjustment(policy.customer, policyBase) + PROCESSING_FEE),
136	  };
137	}
138	
139	export type Damage = {
140	  itemType: string;
141	  amount: number;
142	  componentType?: string;
143	};
144	
145	export type ClaimEvent = {
146	  cause: string;
147	  damages: Damage[];
148	};
149	
150	const DEDUCTIBLE_PER_DAMAGE = 100;
151	
152	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
153	  sword: 1000,
154	  amulet: 600,
155	  staff: 800,
156	  potion: 400,
157	  component: 250,
158	};
159	
160	const insuranceValueForItem = (item: Item): number =>
161	  INSURANCE_VALUE_BY_ITEM_TYPE[item.type as string] ?? 0;
162	
163	const CAP_MULTIPLIER = 2;
164	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
165	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
166	
167	const findPolicyItem = (items: Item[], itemType: string): Item | undefined =>
168	  items.find((item) => item.type === itemType);
169	
170	const reimbursementBeforeDeductible = (damage: Damage, item: Item | undefined): number => {
171	  if (item && (item.enchantment as number) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
172	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
173	  }
174	  return damage.amount;
175	};
176	
177	const damagePayout = (damage: Damage, items: Item[]): number => {
178	  const item = findPolicyItem(items, damage.itemType);
179	  return reimbursementBeforeDeductible(damage, item) - DEDUCTIBLE_PER_DAMAGE;
180	};
181	
182	const totalInsuranceValue = (items: Item[]): number =>
183	  items.reduce((sum, item) => sum + insuranceValueForItem(item), 0);
184	
185	const initialCapFor = (items: Item[]): number =>
186	  CAP_MULTIPLIER * totalInsuranceValue(items);
187	
188	const damageKey = (damage: Damage): string =>
189	  damage.itemType === "component"
190	    ? `component:${damage.componentType as string}`
191	    : damage.itemType;
192	
193	const itemKey = (item: Item): string =>
194	  item.type === "component"
195	    ? `component:${item.componentType as string}`
196	    : (item.type as string);
197	
198	const countByKey = <T>(values: T[], keyFn: (value: T) => string): Map<string, number> => {
199	  const counts = new Map<string, number>();
200	  for (const value of values) {
201	    const key = keyFn(value);
202	    counts.set(key, (counts.get(key) ?? 0) + 1);
203	  }
204	  return counts;
205	};
206	
207	const validateDamageAmounts = (damages: Damage[]): void => {
208	  for (const damage of damages) {
209	    if (damage.amount < 0) {
210	      throw new Error("Damage amount must be non-negative");
211	    }
212	  }
213	};
214	
215	const validateDamageCounts = (items: Item[], damages: Damage[]): void => {
216	  const itemCounts = countByKey(items, itemKey);
217	  const damageCounts = countByKey(damages, damageKey);
218	  for (const [key, count] of damageCounts) {
219	    if (count > (itemCounts.get(key) ?? 0)) {
220	      throw new Error(`More damages of type ${key} than insured`);
221	    }
222	  }
223	};
224	
225	const validateDamages = (items: Item[], damages: Damage[]): void => {
226	  validateDamageAmounts(damages);
227	  validateDamageCounts(items, damages);
228	};
229	
230	export function claim(policy: { items: Item[]; remainingCap?: number }, event: ClaimEvent): ClaimResult {
231	  validateDamages(policy.items, event.damages);
232	  const uncappedPayout = event.damages.reduce(
233	    (sum, damage) => sum + damagePayout(damage, policy.items),
234	    0,
235	  );
236	  const cap = policy.remainingCap ?? initialCapFor(policy.items);
237	  const cappedPayout = Math.min(uncappedPayout, cap);
238	  const payout = Math.floor(cappedPayout);
239	  return { payout, remainingCap: cap - payout };
240	}
